#include <stdio.h>
#include <stdlib.h>
#include <string.h>

char* nextTerm(const char* s){
    int len = strlen(s);
    char* res = (char*)malloc((len*2 + 10) * sizeof(char));
    int pos = 0, cnt = 1;
    for(int i = 0; i < len; ++i){
        if(i + 1 < len && s[i] == s[i+1]) cnt++;
        else{
            pos += sprintf(res + pos, "%d", cnt);
            res[pos++] = s[i];
            cnt = 1;
        }
    }
    res[pos] = '\0';
    return res;
}

char* countAndSay(int n){
    char* cur = (char*)malloc(2);
    strcpy(cur, "1");
    for(int i = 2; i <= n; ++i){
        char* nxt = nextTerm(cur);
        free(cur);
        cur = nxt;
    }
    return cur;
}

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int n; scanf("%d", &n);
        char* ans = countAndSay(n);
        printf("%s\n", ans);
        free(ans);
    }
    return 0;
}

