import sys

def next_term(s):
    res = []
    cnt = 1
    for i in range(len(s)):
        if i + 1 < len(s) and s[i] == s[i+1]:
            cnt += 1
        else:
            res.append(str(cnt))
            res.append(s[i])
            cnt = 1
    return ''.join(res)

def count_and_say(n):
    cur = '1'
    for _ in range(2, n+1):
        cur = next_term(cur)
    return cur

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    T = int(data[0])
    out = []
    idx = 1
    for _ in range(T):
        n = int(data[idx]); idx += 1
        out.append(count_and_say(n))
    sys.stdout.write('\n'.join(out))

if __name__ == '__main__':
    solve()

